      sosEnded = err;
    }),
    pull.flatten()
  )

  read(true, function(err, data) {
    t.equal(err, true)
    t.notOk(data)
    process.nextTick(function() {
      t.equal(sosEnded, null, 'should abort stream of streams')
      t.equal(s1Ended, undefined, 'should abort current nested stream')
